CREATE OR REPLACE VIEW vr_wef_dag_by_day (membership_no, requestment_no, member_group_no, dag_type, danger_type, dag_desc, dag_date, paid_date, total_receive, remark, operate_date, approve_date, wef_type, bank_acc_no, money_type_id, return_status) AS select sc_wef_req.membership_no,
       sc_wef_req.requestment_no,
       sc_mem_m_membership_registered.member_group_no,
       sc_wef_req_dag.dag_type,
       CASE WHEN sc_wef_req_dag.dag_type='01' THEN '01' WHEN sc_wef_req_dag.dag_type='02' THEN '02' WHEN sc_wef_req_dag.dag_type='03' THEN '01' WHEN sc_wef_req_dag.dag_type='04' THEN '02' END  as danger_type,
       sc_wef_rule_dag.dag_desc,
       sc_wef_req_dag.dag_date,
       (select max(paid_date) FROM sc_fin_money_return where sc_wef_req.requestment_no = sc_fin_money_return.refno1) as paid_date,
       sc_wef_req.total_receive,
       sc_wef_req_dag.remark,
       sc_wef_req.operate_date,
       sc_wef_req.approve_date,
       sc_wef_req.wef_type,
       sc_wef_req.bank_acc_no,
       sc_wef_req.money_type_id,
       sc_fin_money_return.return_status
from sc_wef_req,sc_wef_req_dag,sc_wef_rule_dag,sc_mem_m_membership_registered,sc_fin_money_return
